async (params, browser) => {
  // Open page
  await browser.open(`https://letterboxd.com/film/${params.film_slug}/reviews/`)

  // Wait for content
  await browser.waitForSelector('section.film-reviews, div.viewing-list, article.film-detail', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const reviews = Array.from(document.querySelectorAll('article.film-detail, article.production-viewing')).slice(0,15).map(rev => { const reviewer = rev.querySelector('strong.displayname, a.context')?.textContent?.trim()||''; const rating = rev.querySelector('span.rating')?.textContent?.trim()||''; const text = rev.querySelector('div.body-text p')?.textContent?.trim()?.substring(0,500)||''; return { reviewer, rating, text }; }).filter(r=>r.text); return { film: '' + params.film_slug + '', reviews, url: window.location.href }`)

  return page_data
}
